export default function ProfilePic({ mode }) {
  const navigate = useNavigate();
  const { state } = useLocation();
  const Onboarding = useSelector((s) => s.Onboarding);
  const [profilePic, setPic] = useState(Onboarding.profilePic);
  const [about, setAbout] = useState(Onboarding.about);
  const dispatch = useDispatch();

  const uploadImage = (e) => {
    dispatch(updateFeedback({ loading: true }));

    handleuploadImage(e).then(
      (res) => {
        setPic(res.data.Location);
        dispatch(updateFeedback({ loading: false }));
      },
      (rej) => {
        if (rej == "size")
          return dispatch(
            updateFeedback({
              loading: false,
              snackbar: true,
              message: "Image size should be less than 5 mb",
              severity: "warning",
            })
          );
        else
          return dispatch(
            updateFeedback({
              loading: false,
              snackbar: true,
              message: "Error in uploading image please try again later",
              severity: "warning",
            })
          );
      }
    );
  };

  useEffect(() => {
    dispatch(updateOnboarding({ profilePic: profilePic }));
  }, [profilePic, about]);

  const handleNext = () => {
    navigate(
      `/onboarding/${
        mode == "client" ? "client/platform-info" : "platform-info"
      }`,
      {
        state,
      }
    );
  };

  return (
    <Page title="The starting point for your next fitness gig">
      <Input
        accept="image/*"
        onChange={uploadImage}
        id="profile-img"
        cropShape={"round"}
        aspect={1}
        style={{ display: "none" }}
      />
      <Container>
        <Header
          title={"Create new account"}
          onClose={() => navigate("/", { state })}
        />
        <Content>
          <Box
            display={"flex"}
            justifyContent="center"
            alignItems={"center"}
            mt={4}
          >
            <Typography variant="h3" sx={{ color: "grey.700" }}>
              Figgs.co
            </Typography>
            <Box
              sx={{
                ml: 1,
                px: 1,
                backgroundColor: "primary.lighter",
                borderRadius: "30px",
              }}
            >
              {" "}
              <Box sx={{ color: "primary.main", fontSize: 10, py: 0.3 }}>
                Beta
              </Box>
            </Box>
          </Box>
          <Box
            display={"flex"}
            height={"100%"}
            flexDirection={"column"}
            alignItems={"center"}
            pt={2}
          >
            <Box
              width={"100%"}
              display="flex"
              justifyContent={"center"}
              mt={4}
              mb={2}
            >
              <Box
                style={{
                  borderRadius: "50%",
                  position: "relative",

                  backgroundSize: "cover",
                }}
                onClick={() => document.getElementById("profile-img").click()}
              >
                {!profilePic ? (
                  <Avatar sx={{ width: 130, height: 130 }}>
                    <AccountCircleIcon
                      sx={{ fontSize: 155, color: "#E1E7F0" }}
                    />
                  </Avatar>
                ) : (
                  <Avatar
                    sx={{ width: 130, height: 130 }}
                    src={profilePic}
                  ></Avatar>
                )}
                <IconButton
                  sx={{
                    position: "absolute",
                    top: -13,
                    right: -8,
                  }}
                >
                  <AddCircleIcon sx={{ fontSize: 48 }} />
                </IconButton>
              </Box>
            </Box>
          </Box>
          <Stack spacing={2} sx={{ width: "100%" }}>
            <TextField
              fullWidth
              placeholder="Example: Yoga, Strength, Bodybuilding"
              inputProps={{
                maxLength: 70,
              }}
              InputProps={{
                endAdornment: (
                  <InputAdornment position="end" sx={{ height: "100%" }}>
                    <Box>
                      <Typography variant="body2" color="text.secondary">
                        {0 + "/70"}
                      </Typography>
                    </Box>
                  </InputAdornment>
                ),
              }}
              clabel={
                <Typography variant="subtitle1">
                  Speciality
                  {/* <Typography component={"span"} color={"error"}>
                        *
                      </Typography> */}
                </Typography>
              }
            />
            <TextField
              fullWidth
              multiline
              minRows={6}
              sx={{ mb: 2 }}
              inputProps={{
                maxLength: 500,
              }}
              InputProps={{
                endAdornment: (
                  <InputAdornment position="end" sx={{ height: "100%" }}>
                    <Box
                      position={"absolute"}
                      bottom={12}
                      right={16}
                      height={"100%"}
                      display={"flex"}
                      flexDirection="column"
                      justifyContent={"flex-end"}
                      // marginTop={10}
                    >
                      <Typography variant="body2" color="text.secondary">
                        {0 + "/1000"}
                      </Typography>
                    </Box>
                  </InputAdornment>
                ),
              }}
              clabel={
                <Typography variant="subtitle1">
                  About
                  {/* <Typography component={"span"} color={"error"}>
                        *
                      </Typography> */}
                </Typography>
              }
              placeholder="Write down your fitness and health goals"
            />
          </Stack>
        </Content>
        <FooterBase>
          <Footer
            next
            nextText={!profilePic ? "Skip" : "Next"}
            nextClick={handleNext}
          />
        </FooterBase>
      </Container>
    </Page>
  );
}
